INSERT INTO "jeepney_routes" ("id", "name", "description", "direction_note", "color", "fare_regular", "fare_discounted")
VALUES
  ('kaliwa-kanan', 'Kaliwa / Kanan', 'Loop between Olivarez Plaza in Los Baños town and the UPLB academic core, passing Raymundo Gate, the Main Library, the dormitories, and CEAT.', 'Kaliwa and Kanan are the same loop; the name says which way the jeep turns after entering the UPLB gate. Kaliwa turns left and follows the stops as listed (Carabao Park / DevCom first); Kanan turns right and serves the same stops in reverse (Carabao Park / Landbank first).', '#dc2626', 13, 11),
  ('forestry', 'Forestry', 'Connects the campus core to the upper Forestry campus: from the Forestry jeep terminal past the Main Library area, Narra Bridge, and the University Health Service, climbing to the College of Forestry and Natural Resources.', NULL, '#15803d', 13, 11)
