CREATE TABLE IF NOT EXISTS "jeepney_routes" (
  "id" varchar(64) PRIMARY KEY,
  "name" varchar(120) NOT NULL,
  "description" text NOT NULL,
  "direction_note" text,
  "color" varchar(16) NOT NULL,
  "fare_regular" double precision NOT NULL,
  "fare_discounted" double precision NOT NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "version" integer NOT NULL DEFAULT 1,
  "updated_at" timestamp NOT NULL DEFAULT now()
);
--> statement-breakpoint
CREATE TABLE IF NOT EXISTS "jeepney_stops" (
  "id" integer PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  "route_id" varchar(64) NOT NULL REFERENCES "jeepney_routes"("id") ON DELETE CASCADE,
  "name" varchar(160) NOT NULL,
  "description" text NOT NULL,
  "lat" double precision NOT NULL,
  "lon" double precision NOT NULL,
  "sort_order" integer NOT NULL DEFAULT 0,
  "is_active" boolean NOT NULL DEFAULT true,
  "version" integer NOT NULL DEFAULT 1,
  "updated_at" timestamp NOT NULL DEFAULT now(),
  CONSTRAINT "jeepney_stops_route_sort_order" UNIQUE ("route_id", "sort_order")
);
